import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Sayfa Ayarları","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Page/page-settings.md","filePath":"tr-TR/Page/page-settings.md","lastUpdated":1781962217000}'),n={name:"tr-TR/Page/page-settings.md"};function i(l,t,o,s,g,m){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="sayfa-ayarları" tabindex="-1">Sayfa Ayarları <a class="header-anchor" href="#sayfa-ayarları" aria-label="Permalink to &quot;Sayfa Ayarları&quot;">​</a></h1><p>Page settings; site görünümünü, yükleme sayfası varsayılanlarını, arka plan görsellerini ve yönetim paneli görünümünü kontrol eder.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Amaç</th></tr></thead><tbody><tr><td>Site title</td><td>Tarayıcı sekmesinde gösterilen başlık.</td></tr><tr><td>Site icon</td><td>Tarayıcı sekmesinde gösterilen küçük simge.</td></tr><tr><td>ImgBed name</td><td>Frontend pages üzerinde gösterilen ad.</td></tr><tr><td>ImgBed logo</td><td>Frontend pages üzerinde gösterilen logo görseli.</td></tr><tr><td>Logo link</td><td>Logo veya avatar tıklandığında açılan URL.</td></tr><tr><td>Background switch interval</td><td>Birden fazla arka plan için milisaniye cinsinden dönüş aralığı. <code>60000</code>, 60 saniye demektir.</td></tr><tr><td>Background opacity</td><td>Arka plan görseli opaklığı, <code>0</code> ile <code>1</code> arası. Daha düşük değerler daha açık görünür.</td></tr><tr><td>Default URL prefix</td><td>Görsel bağlantıları oluşturulurken kullanılan prefix. Boşsa geçerli site alan adı kullanılır.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Amaç</th></tr></thead><tbody><tr><td>Announcement</td><td>Yükleme sayfasının üstünde gösterilen duyuru. HTML desteklenir.</td></tr><tr><td>Default upload channel</td><td>Yükleme sayfasında varsayılan seçili upload channel. Smart Dispatch de seçilebilir.</td></tr><tr><td>Default upload directory</td><td>Varsayılan yükleme dizini, örneğin <code>/user/</code>. Boş veya <code>/</code> root anlamına gelir.</td></tr><tr><td>Default naming method</td><td>Yükleme sonrası varsayılan dosya adı üretme stratejisi. Aşağıya bakın.</td></tr><tr><td>Convert to WebP by default</td><td>Görselleri yüklemeden önce WebP&#39;ye dönüştürür.</td></tr><tr><td>Enable compression by default</td><td>Görselleri yüklemeden önce tarayıcıda yerel olarak sıkıştırır.</td></tr><tr><td>Default compression threshold</td><td>Görsel bu boyutu MB cinsinden aşarsa otomatik sıkıştırır.</td></tr><tr><td>Default target size</td><td>Sıkıştırma sonrası hedef dosya boyutu, MB cinsinden.</td></tr><tr><td>Login page background</td><td>Kullanıcı giriş sayfası arka plan görseli.</td></tr><tr><td>Upload page background</td><td>Yükleme sayfası arka plan görseli.</td></tr><tr><td>Footer portal link</td><td>Footer portal düğmesinin açtığı URL.</td></tr><tr><td>Hide footer</td><td>Etkin olduğunda frontend footer gizlenir.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Amaç</th></tr></thead><tbody><tr><td>Admin login background</td><td>Yönetici giriş sayfası arka plan görseli.</td></tr><tr><td>Admin background</td><td>Yönetim sayfaları arka plan görseli. Tek image URL veya birden çok URL kullanılabilir.</td></tr><tr><td>Image loading mode</td><td>Yönetim dosya listesindeki preview yükleme modu. Original özgün görselleri yükler. Smart loading public images için thumbnails, restricted images için originals tercih eder.</td></tr><tr><td>Thumbnail source</td><td>Thumbnail oluşturma servisi: wsrv.nl, Cloudflare Image Resizing veya WordPress Photon. Cloudflare Image Resizing seçmeden önce Cloudflare&#39;da etkin olmalıdır.</td></tr><tr><td>Live2D widget</td><td>Yönetim panelinde Live2D karakter gösterir.</td></tr><tr><td>Firework click effect</td><td>Sayfaya tıklanınca havai fişek efekti gösterir.</td></tr><tr><td>Star cursor trail</td><td>Fare hareket ederken yıldız izi gösterir.</td></tr></tbody></table><h2 id="arka-plan-gorseli-formatları" tabindex="-1">Arka Plan Görseli Formatları <a class="header-anchor" href="#arka-plan-gorseli-formatları" aria-label="Permalink to &quot;Arka Plan Görseli Formatları&quot;">​</a></h2><p>Login page background, upload page background ve admin login background şu formatları destekler:</p><table tabindex="0"><thead><tr><th>Değer</th><th>Etki</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Bing duvar kağıdı rotasyonunu kullanır.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Birden fazla görseli döndürür.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Tek arka plan görseli kullanır.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Random image API link kullanır. Other Settings içinde kendi Random Image API&#39;nizi yapılandırıp üretilen random image link değerini tek arka plan girdisi olarak buraya yapıştırabilirsiniz.</td></tr></tbody></table><p>Admin background image URLs destekler. Birden fazla URL, sayfadaki ipucunda belirtildiği gibi İngilizce virgülle ayrılabilir. Boşsa default background kullanılır.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, örneğin <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Yalnızca time-random prefix ve extension, örneğin <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Original filename korunur, örneğin <code>cat.png</code>. Aynı ad varsa ImgBed <code>(1)</code>, <code>(2)</code> ve devamını ekler.</td></tr><tr><td>Short link</td><td>8 karakterlik short ID ve extension kullanır, örneğin <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=e(n,[["render",i]]);export{k as __pageData,u as default};
